#!/usr/bin/env python3
from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import parse_qs
import subprocess
import threading
import time
import json
import re

class SetupHandler(BaseHTTPRequestHandler):
    
    # Captive Portal 检测 URL 列表
    CAPTIVE_PORTAL_PATHS = [
        '/generate_204',           # Android
        '/gen_204',                # Android
        '/hotspot-detect.html',    # iOS/macOS
        '/library/test/success.html',  # iOS
        '/ncsi.txt',               # Windows
        '/connecttest.txt',        # Windows
        '/redirect',               # Windows
        '/success.txt',            # Firefox
    ]
    
    def do_GET(self):
        # 检查是否是 Captive Portal 检测请求
        if self.path in self.CAPTIVE_PORTAL_PATHS or self.is_captive_portal_request():
            self.serve_captive_redirect()
        elif self.path == '/':
            self.serve_main_page()
        elif self.path == '/scan':
            self.serve_wifi_list()
        elif self.path == '/api/scan':
            self.api_scan_wifi()
        else:
            # 其他未知路径也重定向到配网页面（Captive Portal 行为）
            self.serve_captive_redirect()
    
    def is_captive_portal_request(self):
        """检查是否是 Captive Portal 检测请求"""
        host = self.headers.get('Host', '')
        captive_hosts = [
            'captive.apple.com',
            'www.apple.com',
            'connectivitycheck.gstatic.com',
            'connectivitycheck.android.com',
            'clients3.google.com',
            'www.msftconnecttest.com',
            'www.msftncsi.com',
            'nmcheck.gnome.org',
            'network-test.debian.org',
        ]
        return any(h in host for h in captive_hosts)
    
    def serve_captive_redirect(self):
        """返回 Captive Portal 重定向响应"""
        # 302 重定向到配网页面
        self.send_response(302)
        self.send_header('Location', 'http://192.168.1.1/')
        self.send_header('Cache-Control', 'no-cache, no-store, must-revalidate')
        self.send_header('Pragma', 'no-cache')
        self.send_header('Expires', '0')
        self.end_headers()
    
    def serve_main_page(self):
        """主配网页面"""
        self.send_response(200)
        self.send_header('Content-type', 'text/html; charset=utf-8')
        self.end_headers()
        
